#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
static unsigned char buf[8];
static unsigned char obuf[64];
int main(int argc,char**argv){
 int maxlen = argc>=2 ? atoi(argv[1]) : 3;
 for(int len=1;len<=maxlen;len++){
  long total=1; for(int i=0;i<len;i++) total*=256;
  for(long v=0;v<total;v++){
   long x=v; for(int i=0;i<len;i++){buf[i]=x&0xff;x>>=8;}
   FILE *f=fopen("/tmp/b.in","wb"); if(!f) continue; fwrite(buf,1,len,f); fclose(f);
   int pid=fork();
   if(pid==0){
    freopen("/tmp/b.in","rb",stdin);
    freopen("/tmp/b.out","wb",stdout);
    freopen("/dev/null","w",stderr);
    execl("/app/decomp","/app/decomp",(char*)0);
    _exit(127);
   }
   int status=0; waitpid(pid,&status,0);
   FILE *o=fopen("/tmp/b.out","rb"); if(!o) continue;
   int got=0,ch; while((ch=fgetc(o))!=EOF && got<64) obuf[got++]=ch; fclose(o);
   if(got>0){
    int ok=1; for(int b=0;b<got;b++) if(obuf[b]==0) ok=0; // roughly check nonempty non-nul; remove if nul outputs matter
