     printf("len=%d v=%ld bytes",len,v);
     for(int i=0;i<len;i++) printf(" %02x",buf[i]);
     printf(" got=%d out:",got);
     for(int b=0;b<got;b++) printf(" %02x",obuf[b]);
     printf(" status=%d\n",status);
     fflush(stdout);
    }
   }
  }
 }
 return 0;
}
